DELETE FROM G_INQ_CFG WHERE SQL_ID='050149902' and CORP_ID='ALL';
INSERT INTO G_INQ_CFG (CORP_ID,SQL_ID,SQL_STRING,DETAIL_SQL_STRING,SYSTEM,REMARKS,UPD_TIME,CRT_TIME,RSV1,RSV2,RSV3,RSV4,RSV5) VALUES ('ALL','050149902','select brno,CIPS_WARN_AMT,INER_WARN_AMT as INNER_WARN_AMT,
  case (select case when sys_status in (''CLSD'', ''ACTV'', ''SUSP'', ''CLSG'') then ''DAYT'' else  ''NITT'' end as day_night_flg from  GPAY_SYS_STATUS where SYS_CODE=''CIPS'') when ''DAYT'' then DAYT_CIPS_BAL_AMT else  NITT_CIPS_BAL_AMT end as CIPS_BAL_AMT,
  case (select case when sys_status in (''CLSD'', ''ACTV'', ''SUSP'', ''CLSG'') then ''DAYT'' else  ''NITT'' end as day_night_flg from  GPAY_SYS_STATUS where SYS_CODE=''CIPS'') when ''DAYT'' then DAYT_INER_BAL_AMT else  NITT_INER_BAL_AMT end as INNER_BAL_AMT,
  case (select case when sys_status in (''CLSD'', ''ACTV'', ''SUSP'', ''CLSG'') then ''DAYT'' else  ''NITT'' end as day_night_flg from  GPAY_SYS_STATUS where SYS_CODE=''CIPS'') when ''DAYT'' then DAYT_INER_DNS_AMT else  NITT_INER_DNS_AMT end as INNER_DNS_AMT
from CIPS_INNER_BRINFO ',null,'CIPS',null,null,null,null,null,null,null,null);

