--[-+]
DELETE FROM G_INQ_CFG WHERE SQL_ID='051090501' and CORP_ID='ALL';
INSERT INTO G_INQ_CFG (CORP_ID,SQL_ID,SQL_STRING,DETAIL_SQL_STRING,SYSTEM,REMARKS,UPD_TIME,CRT_TIME,RSV1,RSV2,RSV3,RSV4,RSV5) VALUES ('ALL','051090501','SELECT
    case when a.PROC_STATUS=''01'' then ''未处理,''||a.PAYMENT_REMARK
         when a.PROC_STATUS=''02'' then ''已同意,''||a.PAYMENT_REMARK
         when a.PROC_STATUS=''03'' then ''已拒绝,''||a.PAYMENT_REMARK
        end as PROC_INFO,
		a.PAYMENT_REMARK,
    case when a.MSG_ID_112 is not null then a.MSG_ID_112 ||'',''|| a.PBOC_STATUS_112 end as MSG_112_INFO,
    a.TXN_SEQ_NO,
    b.CHRGS_DTL_SEQNO ||'',''|| c.TXN_DTL_SEQNO AS DTL_SEQNO,
    c.MSG_ID as OTXN_MSG_ID,
    a.CTRL_SUM_AMT,
    b.CHRGS_ACCT_AGT_CLR_SYS_MMBID,
    b.CHRGS_AC_AGT_AC_OTH_ID,
    b.CHRGS_AC_AGT_AC_NAME,
    a.SND_ST_BRNO,
    a.MSG_ID,
    a.WORK_DATE,
    a.MSG_SND_TIME,
    d.MADE_USER,
    d.MADE_TIME,
    d.CENTER_DATE,
    d.PBOC_STATUS,
    c.SEQ_NO as DTL_SEQ_NO,
    a.SEQ_NO,
    d.REF_NO,
    d.CORE_PROC_STATUS
FROM
    cips_info d,
    cips_109 a,
    cips_109_list b,
    cips_109_dlist c
WHERE
        d.TXN_SEQ_NO = a.TXN_SEQ_NO
  AND a.SEQ_NO = b.P_SEQ_NO
  AND b.SEQ_NO = c.P_SEQ_NO
  AND a.TXN_DIR = ''2''
  AND ((d.CENTER_DATE is not null and d.center_date >= :"START_CENTER_DATE") or d.CENTER_DATE is null)
  AND ((d.CENTER_DATE is not null and d.center_date <= :"END_CENTER_DATE") or d.CENTER_DATE is null)
  AND c.MSG_ID =:"OTXN_MSG_ID"
  AND a.PROC_STATUS = :"PROC_STATUS"
  AND a.TXN_SEQ_NO = :"TXN_SEQ_NO"
  AND a.MSG_ID = :"MSG_ID"
order by a.SEQ_NO desc, b.SEQ_NO,c.SEQ_NO',null,'CIPS',null,null,null,null,null,null,null,null);

