INSERT INTO G_INQ_CFG (CORP_ID,SQL_ID,SQL_STRING,DETAIL_SQL_STRING,SYSTEM,REMARKS,UPD_TIME,CRT_TIME,RSV1,RSV2,RSV3,RSV4,RSV5) VALUES ('ALL','051140101','select WORK_DATE,
       CENTER_DATE,
       TXN_SEQ_NO,
       MSG_ID,
       MSG_TYPE,
       BIZ_CATE_CODE,
       AMT,
       PAYER_ST_BRNO,
       PAYER_BRNO,
       PAYER_ACCT_BRNO,
       PAYER_ACCT_BRNAME,
       PAYER_ACTNO,
       PAYER_NAME,
       PAYEE_ST_BRNO,
       PAYEE_BRNO,
       PAYEE_ACCT_BRNO,
       PAYEE_ACCT_BRNAME,
       PAYEE_ACTNO,
       PAYEE_NAME,
       E2E_ID,
       msg_NO
from cips_txn
where TXN_DIR = ''2''
  and TXN_SEQ_NO = :"TXN_SEQ_NO"
  and MSG_ID = :"MSG_ID"
  and WORK_DATE = :"WORK_DATE"
  and CENTER_DATE = :"CENTER_DATE"
  and AMT = :"AMT"
  and msg_no in (''111'', ''112'', ''113'') order by TXN_SEQ_NO desc',null,'CIPS',null,null,null,null,null,null,null,null);

--[-+]
DELETE FROM G_INQ_CFG WHERE SQL_ID='051140201' and CORP_ID='ALL';
INSERT INTO G_INQ_CFG (CORP_ID,SQL_ID,SQL_STRING,DETAIL_SQL_STRING,SYSTEM,REMARKS,UPD_TIME,CRT_TIME,RSV1,RSV2,RSV3,RSV4,RSV5) VALUES ('ALL','051140201','SELECT a.txn_seq_no,
       b.seq_no,
       a.msg_no,
       a.work_date,
       a.txn_dir,
       a.msg_id,
       a.pboc_status,
       a.comm_status,
       a.payer_actno,
       a.payer_name,
       a.payee_actno,
       a.payee_name,
       CASE WHEN a.txn_dir = ''1'' THEN a.rcv_st_brno ELSE a.snd_st_brno END     AS op_st_brno,
       CASE WHEN a.txn_dir = ''1'' THEN a.rcv_st_brname ELSE a.snd_st_brname END AS op_st_brname,
       b.RTRD_INSTD_AMT as b.AMT,
       b.ORGNL_MSG_NM_ID,
       b.ORGNL_MSG_ID
FROM cips_txn a left join cips_114 b
on a.SEQ_NO=b.SEQ_NO
WHERE a.msg_no = ''114''
  AND a.next_flow = ''S30''
  AND a.WORK_DATE = :"WORK_DATE"
  AND a.TXN_SEQ_NO = :"TXN_SEQ_NO"
  AND a.MADE_USER = :"MADE_USER"
  AND a.TXN_DIR = ''1''
  AND a.AMT >= :"START_AMT"
  AND a.AMT <= :"END_AMT"
  AND a.TXN_STATUS = :"TXN_STATUS"
  AND a.ORG_ID = :"HEAD.ORG_ID"
  AND b.ORGNL_MSG_ID = :"OTXN_MSG_ID"
order by a.TXN_SEQ_NO desc',null,'CIPS',null,null,null,null,null,null,null,null);

