--[-+]
DELETE FROM G_INQ_CFG WHERE SQL_ID='053560001' and CORP_ID='ALL';
INSERT INTO G_INQ_CFG (CORP_ID,SQL_ID,SQL_STRING,DETAIL_SQL_STRING,SYSTEM,REMARKS,UPD_TIME,CRT_TIME,RSV1,RSV2,RSV3,RSV4,RSV5) VALUES ('ALL','053560001','SELECT
    D .TXN_SEQ_NO,
    D .SEQ_NO,
    D .CENTER_DATE,
    D .WORK_DATE,
    D .MADE_USER,
    D .CRT_TIME,
    D.DAY_NIGHT_FLG,
    D.COMM_STATUS,
    D.PBOC_STATUS,
    D.MSG_ID,
    CASE
        WHEN D.NEXT_FLOW=''S93'' THEN
            4
        WHEN D.CENTER_DATE IS NULL THEN
            3
        WHEN c.SEQ_NO IS NULL THEN
            0
        WHEN c.PBOC_STATUS IS NULL THEN
            1
        ELSE
            2
        END AS IS_INQ_SUCCESS
FROM
    (
        SELECT
            A.SEQ_NO,
            A.TXN_SEQ_NO,
            A.RT_SEQ_NO,
            A.CRT_TIME,
            A.WORK_DATE,
            A.CENTER_DATE,
            A.MADE_USER,
            A.NEXT_FLOW,
            A.COMM_STATUS,
            b.PBOC_STATUS,
            b.DAY_NIGHT_FLG,
            b.MSG_ID
        FROM
            CIPS_INFO A,
            CIPS_356 b
        WHERE
                1 = 1
          AND A.MSG_NO = ''356''
          AND A.SEQ_NO = b.SEQ_NO
          AND A.CENTER_DATE=:"CENTER_DATE"
          AND A.WORK_DATE = :"WORK_DATE"
          AND b.DAY_NIGHT_FLG = :"DAY_NIGHT_FLG"
          AND A.TXN_SEQ_NO = :"TXN_SEQ_NO"
    ) D
        LEFT JOIN CIPS_357 c ON D .rt_seq_no = c.seq_no order by d.crt_time desc',null,'CIPS',null,null,null,null,null,null,null,null);

