  a.txn_seq_no,
  a.seq_no,
  a.work_date,
  a.center_date,
  a.msg_id,
  a.msg_snd_time,
  a.day_night_flg,
  a.COMM_STATUS,
  a.PBOC_STATUS,
  (select count(*) from cips_374_list b where b.P_SEQ_NO = a.seq_no) as INJ_SUCD_CNT
  from cips_374 a 
where 
  1=1 and a.center_date >= :"START_CENTER_DATE" and a.center_date <= :"END_CENTER_DATE" 
  and a.DAY_NIGHT_FLG = :"DAY_NIGHT_FLG" and a.MSG_ID = :"MSG_ID" order by a.work_date desc',null,'CIPS',null,null,null,null,null,null,null,null);

