where center_date >= :"start_center_date" AND
      center_date <= :"end_center_date"  AND CHNG_TERM=:"CHNG_TERM" AND MSG_ID = :"MSG_ID" order by seq_no desc',null,'CIPS',null,null,null,null,null,null,null,null);

--[-+]
DELETE FROM G_INQ_CFG WHERE SQL_ID='056111001' and CORP_ID='ALL';
INSERT INTO G_INQ_CFG (CORP_ID,SQL_ID,SQL_STRING,DETAIL_SQL_STRING,SYSTEM,REMARKS,UPD_TIME,CRT_TIME,RSV1,RSV2,RSV3,RSV4,RSV5) VALUES ('ALL','056111001','select m.*,
       case
           when n.BIZ_PROC_STATUS is null then ''待扣''
           when n.BIZ_PROC_STATUS = ''SUCD'' then ''扣费成功''
           when n.BIZ_PROC_STATUS = ''RJCT'' then ''扣费失败'' end as STATUS,
       n.MSG_ID                                            as MSG_ID_612
from (
         select a.TXN_SEQ_NO,
                a.MSG_ID,
                a.CENTER_DATE                                                       as CENTER_DATE_611,
                case when a.CCY = ''HKD'' then ''港元业务'' else ''人民币业务'' end                as BIZ_TYPE,
                a.DELAYED_DEBIT_DATE,
                (case when a.M_SYS_OP_AMT is null then 0 else a.M_SYS_OP_AMT end +
                 case when a.M_MSG_PRO_AMT is null then 0 else a.M_MSG_PRO_AMT end +
                 case when a.M_OTH_AMT is null then 0 else a.M_OTH_AMT end) as MONTH_SUM_AMT,
                (case when a.Y1_AMT is null then 0 else a.Y1_AMT end +
                 case when a.Y2_AMT is null then 0 else a.Y2_AMT end) as YEAR_AMT,
             c.CENTER_DATE_612,
             c.ORI_MSG_ID
         from cips_611 a
             left outer join
             (
             select max(b.CENTER_DATE) as CENTER_DATE_612,
             b.ORI_MSG_ID
             from cips_612 b
             group by b.ORI_MSG_ID
             ) c on c.ORI_MSG_ID = a.MSG_ID
         where 1 = 1 and a.CENTER_DATE>=:"START_611_DATE" and a.CENTER_DATE<=:"END_611_DATE" AND a.MSG_ID = :"MSG_ID") m
         left join cips_612 n on m.MSG_ID = n.ORI_MSG_ID and m.CENTER_DATE_612 = n.CENTER_DATE
order by m.TXN_SEQ_NO desc',null,'CIPS',null,null,null,null,null,null,null,null);

