  idptNum = idptNum + 1
end
if  #valid.object["PRE_AGT2_ID"] ~= 0 or #valid.object["PRE_AGT2_ID_SCHEX"] ~= 0 then
  idptNum = idptNum + 1
end
if  #valid.object["PRE_AGT3_ID"] ~= 0 or #valid.object["PRE_AGT3_ID_SCHEX"] ~= 0 then
  idptNum = idptNum + 1
end
return idptNum > 1','pass',null,null,null,null,'valid.error(valid.config.name)
